package exam01_PrimitiveDataType;

public class PDT02_float {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		// float
		System.out.println(3.13F);
		System.out.println(3.13f);
		
		System.out.println("=====");
		// double
		System.out.println(3.13D);
		System.out.println(3.13d);
		System.out.println(3.13);

	}

}
